import type { EnemyConfig, StageConfig, WaveConfig } from '../types';

const makeWaves = (difficulty: number): WaveConfig[] => [
  { time: 1, spawn: difficulty % 2 === 0 ? 'drone' : 'scout', count: 7 + difficulty, pattern: 'line', intervalMs: Math.max(160, 360 - difficulty * 20) },
  { time: 8, spawn: 'drone', count: 8 + difficulty, pattern: 'vee', intervalMs: Math.max(150, 310 - difficulty * 16) },
  { time: 18, spawn: 'scout', count: 10 + difficulty, pattern: 'sine', intervalMs: Math.max(130, 240 - difficulty * 10) },
  { time: 32, spawn: 'gunship', count: 5 + Math.ceil(difficulty / 2), pattern: 'ambush', intervalMs: Math.max(360, 640 - difficulty * 26) },
  { time: 54, spawn: 'midboss', count: 1, pattern: difficulty >= 4 ? 'sine' : 'line', x: 216 },
  { time: 73, spawn: 'boss', count: 1, pattern: 'boss', x: 216 },
];

