import Phaser from 'phaser';
import { GAME_HEIGHT, GAME_WIDTH } from '../constants';

export class MenuScene extends Phaser.Scene {
  constructor() {
    super('MenuScene');
  }

  create(): void {
    this.add.image(GAME_WIDTH / 2, GAME_HEIGHT / 2, 'menu-background-premium').setAlpha(1);
    this.add.rectangle(GAME_WIDTH / 2, GAME_HEIGHT / 2, GAME_WIDTH, GAME_HEIGHT, 0x020611, 0.16);
    this.add.rectangle(GAME_WIDTH / 2, 210, GAME_WIDTH, 260, 0x020611, 0.22);

    this.add
      .text(GAME_WIDTH / 2, 168, 'SKY RAIDER', {
        fontFamily: 'Arial, sans-serif',
        fontSize: '52px',
        color: '#ffffff',
        fontStyle: 'bold',
      })
      .setOrigin(0.5);

    this.add
      .text(GAME_WIDTH / 2, 224, '8-Stage AI Art Demo', {
        fontFamily: 'Arial, sans-serif',
        fontSize: '18px',
        color: '#bff7ff',
      })
      .setOrigin(0.5);

    this.add
      .text(GAME_WIDTH / 2, 254, '霓虹空戰計畫', {
        fontFamily: 'Arial, sans-serif',
        fontSize: '16px',
        color: '#ffe4a8',
      })
      .setOrigin(0.5);

    const start = this.add
      .text(GAME_WIDTH / 2, 704, 'TAP TO LAUNCH', {
        fontFamily: 'Arial, sans-serif',
        fontSize: '24px',
        color: '#fff4b8',
        fontStyle: 'bold',
      })
      .setOrigin(0.5);

    this.tweens.add({ targets: start, alpha: 0.35, yoyo: true, repeat: -1, duration: 650 });
    this.input.once('pointerdown', () => this.scene.start('GameScene'));
    this.input.keyboard?.once('keydown-SPACE', () => this.scene.start('GameScene'));
  }
}
